  2→import { authHandshake, authWithRetry } from "wow/auth";
  3→import { worldSession } from "wow/client";
  4→import type { WorldHandle } from "wow/client";
  5→import { RingBuffer } from "lib/ring-buffer";
  6→import { socketPath, pidPath, runtimeDir, logPath } from "lib/paths";
  7→import { SessionLog } from "lib/session-log";
  8→import { mkdir, writeFile, unlink } from "node:fs/promises";
  9→import {
 10→  parseIpcCommand,
 11→  dispatchCommand,
 12→  onChatMessage,
 13→  onGroupEvent,
 14→  onEntityEvent,
 15→  onFriendEvent,
 16→  onIgnoreEvent,
 17→  onGuildEvent,
 18→  writeLines,
 19→  type EventEntry,
 20→  type IpcSocket,
 21→} from "daemon/commands";
 22→
 23→type SocketState = { buffer: string; processing: boolean; ended: boolean };
 24→
 25→type ServerCtx = {
 26→  handle: WorldHandle;
 27→  events: RingBuffer<EventEntry>;
 28→  cleanup: () => void;
 29→  onActivity?: () => void;
 30→  onStop?: () => void;
 31→};
 32→
 33→type DaemonServerArgs = {
 34→  handle: WorldHandle;
 35→  sock: string;
 36→  log: SessionLog;
 37→  onActivity?: () => void;
 38→  onStop?: () => void;
 39→};
 40→
 41→type DaemonServer = {
 42→  server: ReturnType<typeof Bun.listen>;
 43→  events: RingBuffer<EventEntry>;
 44→  cleanup: () => void;
 45→};
 46→
 47→type DaemonClient = {
 48→  authHandshake: typeof authHandshake;
 49→  worldSession: typeof worldSession;
 50→};
 51→
 52→const socketStates = new WeakMap<IpcSocket, SocketState>();
 53→
 54→function getSocketState(socket: IpcSocket): SocketState {
 55→  const existing = socketStates.get(socket);
 56→  if (existing) return existing;
 57→  const state: SocketState = { buffer: "", processing: false, ended: false };
 58→  socketStates.set(socket, state);
 59→  return state;
 60→}
 61→
 62→function drainNextLine(ctx: ServerCtx, socket: IpcSocket): void {
 63→  const state = getSocketState(socket);
 64→  state.processing = false;
 65→  if (state.ended) return;
 66→  const nextBreak = state.buffer.indexOf("\n");
 67→  if (nextBreak !== -1) {
 68→    const next = state.buffer.slice(0, nextBreak).trim();
 69→    state.buffer = state.buffer.slice(nextBreak + 1);
 70→    processLine(ctx, socket, next);
 71→    return;
 72→  }
 73→  state.ended = true;
 74→  socket.end();
 75→}
 76→
 77→function processLine(ctx: ServerCtx, socket: IpcSocket, line: string): void {
 78→  const state = getSocketState(socket);
 79→  if (state.processing || state.ended) return;
 80→  state.processing = true;
 81→  ctx.onActivity?.();
 82→  const cmd = parseIpcCommand(line);
 83→  if (!cmd) {
 84→    writeLines(socket, ["ERR unknown command"]);
 85→    state.ended = true;
 86→    state.processing = false;
 87→    socket.end();
 88→    return;
 89→  }
 90→  dispatchCommand(cmd, ctx.handle, ctx.events, socket, ctx.cleanup)
 91→    .then((shouldExit) => {
 92→      if (shouldExit) (ctx.onStop ?? (() => process.exit(0)))();
 93→    })
 94→    .catch(() => writeLines(socket, ["ERR internal"]))
 95→    .finally(() => drainNextLine(ctx, socket));
 96→}
 97→
 98→function onSocketData(ctx: ServerCtx, socket: IpcSocket, data: Buffer): void {
 99→  const state = getSocketState(socket);
100→  state.buffer += Buffer.from(data).toString();
101→  const breakIdx = state.buffer.indexOf("\n");
102→  if (breakIdx === -1) return;
103→  const line = state.buffer.slice(0, breakIdx).trim();
104→  state.buffer = state.buffer.slice(breakIdx + 1);
105→  processLine(ctx, socket, line);
106→}
107→
108→export function startDaemonServer(args: DaemonServerArgs): DaemonServer {
109→  const { handle, sock, log, onActivity, onStop } = args;
110→  const events = new RingBuffer<EventEntry>(1000);
111→  handle.onMessage((msg) => onChatMessage(msg, events, log));
112→  handle.onGroupEvent((event) => onGroupEvent(event, events, log));
113→  handle.onEntityEvent((event) => onEntityEvent(event, events, log));
