  describe("guild handlers", () => {
    function buildGuildRosterPacket(): Uint8Array {
      const w = new PacketWriter();
      w.uint32LE(1);
      w.cString("Welcome!");
      w.cString("Guild info");
      w.uint32LE(1);
      w.uint32LE(0);
      w.uint32LE(0);
      for (let j = 0; j < 6; j++) {
        w.uint32LE(0);
        w.uint32LE(0);
      }
      w.uint64LE(10n);
      w.uint8(1);
      w.cString("Thrall");
      w.uint32LE(0);
      w.uint8(80);
      w.uint8(7);
      w.uint8(0);
      w.uint32LE(1519);
      w.cString("Warchief");
      w.cString("");
      return w.finish();
    }

    function buildGuildQueryResponsePacket(): Uint8Array {
      const w = new PacketWriter();
      w.uint32LE(1);
      w.cString("Horde Elite");
      w.cString("Guild Master");
      w.cString("Officer");
      for (let i = 0; i < 8; i++) {
        w.cString("");
      }
      return w.finish();
    }

