        expect(event.type).toBe("guild-roster");
        expect(event.roster.motd).toBe("Welcome!");
        expect(event.roster.members).toHaveLength(1);
        expect(event.roster.members[0]!.name).toBe("Thrall");

        handle.close();
        await handle.closed;
      } finally {
        ws.stop();
      }
    });

